public static boolean IsWMSLocationReceiptRequired(ItemId _itemId)
{
    InventDimGroupFieldSetup inventDimGroupFieldSetup = EcoResDimensionGroupSetup::getFieldSetupForItem(_itemId, fieldNum(InventDim, WMSLocationId));

    if (!inventDimGroupFieldSetup.dimFieldId()
     || !inventDimGroupFieldSetup.isActive()
     ||  inventDimGroupFieldSetup.isAllowBlankReceiptEnabled())
    {
        return false;
    }

    return true;
}
